SELECT p.amount, r.rental_id, r.inventory_id, i.film_id, f.film_id, fc.category_id, c.name, r.rental_date FROM payment p JOIN rental r ON p.rental_id = r.rental_id JOIN inventory i ON r.inventory_id = i.inventory_id JOIN film f ON i.film_id = f.film_id JOIN film_category fc ON f.film_id = fc.film_id JOIN category c ON fc.category_id = c.category_id WHERE c.name = 'Drama' AND r.rental_date BETWEEN '2005-05-01' AND '2005-05-31'